using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerResourceType]
public class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["database"] = new { Host = "db.example.com", Port = 5432, Name = "appdb" },
        ["features"] = new { DarkMode = true, MaxUploadSizeMb = 50, MaintenanceWindow = "Sun 02:00-04:00 UTC" },
        ["logging"]  = new { Level = "Information", Sink = "console+seq" },
    };

    [McpServerResource(UriTemplate = "config://app/settings",
        Name = "app-settings",
        Title = "Application Settings",
        MimeType = "application/json")]
    public static string GetAllSettings()
    {
        return JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/settings/{section}",
        Name = "app-settings-section",
        Title = "Application Settings Section",
        MimeType = "application/json")]
    public static string GetSettingsSection(string section)
    {
        if (AppConfig.TryGetValue(section, out var value))
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });

        return JsonSerializer.Serialize(new { error = $"Unknown section '{section}'" });
    }
}

