using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerToolType]
public class WeatherTools
{
    private static readonly Dictionary<string, (int TempC, string Condition)> Forecasts = new()
    {
        ["seattle"]   = (18, "Cloudy"),
        ["new york"]  = (25, "Sunny"),
        ["london"]    = (15, "Rainy"),
        ["tokyo"]     = (28, "Humid"),
    };

    [McpServerTool(Name = "get_weather"), Description("Get the current weather for a city.")]
    public static string GetWeather(
        [Description("City name (e.g. 'Seattle')")] string city)
    {
        var key = city.ToLowerInvariant();
        if (Forecasts.TryGetValue(key, out var forecast))
            return $"{city}: {forecast.TempC}°C, {forecast.Condition}";

        return $"No weather data available for '{city}'.";
    }
}

